-- Validate plugin code for basic safety checks
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" then
        return false, "Plugin code must be a non-empty string"
    end

    if #code > 65536 then
        return false, "Plugin code exceeds maximum size of 64KB"
    end

    -- Check for dangerous patterns
    local dangerous_patterns = {
        { pattern = "os%.", msg = "Access to 'os' module is forbidden" },
        { pattern = "io%.", msg = "Access to 'io' module is forbidden" },
        { pattern = "loadfile", msg = "Use of 'loadfile' is forbidden" },
        { pattern = "dofile", msg = "Use of 'dofile' is forbidden" },
        { pattern = "require%s*%(?%s*['\"]ffi", msg = "Access to FFI is forbidden" },
        { pattern = "rawset", msg = "Use of 'rawset' is forbidden" },
        { pattern = "rawget", msg = "Use of 'rawget' is forbidden" },
        { pattern = "setmetatable", msg = "Use of 'setmetatable' is forbidden" },
        { pattern = "getmetatable", msg = "Use of 'getmetatable' is forbidden" },
        { pattern = "debug%.", msg = "Access to 'debug' module is forbidden" },
        { pattern = "package%.", msg = "Access to 'package' module is forbidden" },
        { pattern = "_G", msg = "Access to '_G' is forbidden" },
        { pattern = "getfenv", msg = "Use of 'getfenv' is forbidden" },
        { pattern = "setfenv", msg = "Use of 'setfenv' is forbidden" },
        { pattern = "collectgarbage", msg = "Use of 'collectgarbage' is forbidden" },
        { pattern = "coroutine%.", msg = "Access to 'coroutine' module is forbidden" },
    }

    for _, check in ipairs(dangerous_patterns) do
        if string.find(code, check.pattern) then
            return false, check.msg
        end
    end

    return true, nil
end

-- Compile plugin code with sandboxing
local function compile_plugin(code, plugin_name)
    local ok, err = validate_plugin_code(code)
    if not ok then
        return nil, "Validation failed for plugin '" .. (plugin_name or "unknown") .. "': " .. err
    end

    -- Use load() (LuaJIT/Lua 5.1+ compatible)
    local load_func = load or loadstring
    local chunk, compile_err = load_func(code, "plugin:" .. (plugin_name or "anonymous"))
    if not chunk then
        return nil, "Compilation failed for plugin '" .. (plugin_name or "unknown") .. "': " .. compile_err
    end

    return chunk, nil
end

-- Execute a compiled plugin chunk within a sandbox
local function execute_plugin(chunk, plugin_name, request_ctx)
    local sandbox = create_sandbox_env(request_ctx)

    -- Set the sandbox as the function environment
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(chunk, sandbox)
    end

    -- Execute the chunk to get the plugin table/function
    local ok, plugin_or_err = pcall(chunk)
    if not ok then
        return nil, "Execution failed for plugin '" .. (plugin_name or "unknown") .. "': " .. tostring(plugin_or_err)
    end

    return plugin_or_err, nil
end

-- Connect to Redis
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. tostring(err)
    end

    if REDIS_PASSWORD then
        local auth_ok, auth_err = red:auth(REDIS_PASSWORD)
        if not auth_ok then
            return nil, "Redis authentication failed: " .. tostring(auth_err)
        end
    end

    return red, nil
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if not red then return end
    local ok, err = red:set_keepalive(10000, 100)
    if not ok then
        ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", tostring(err))
    end
end

-- Load plugin code from Redis
local function load_plugin_from_redis(plugin_name)
    -- Check shared dict cache first
    if plugin_cache then
        local cached_code = plugin_cache:get("code:" .. plugin_name)
        if cached_code then
            ngx.log(ngx.DEBUG, "Plugin '", plugin_name, "' loaded from cache")
            return cached_code, nil
        end
    end

    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local code, redis_err = red:get(key)
    release_redis_connection(red)

    if not code then
        return nil, "Redis GET failed for plugin '" .. plugin_name .. "': " .. tostring(redis_err)
    end

    if code == ngx.null then
        return nil, "Plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Cache the code in shared dict
    if plugin_cache then
        local ok, cache_err = plugin_cache:set("code:" .. plugin_name, code, PLUGIN_CACHE_TTL)
        if not ok then
            ngx.log(ngx.WARN, "Failed to cache plugin '", plugin_name, "': ", tostring(cache_err))
        end
    end

    return code, nil
end

-- Load plugin code from HTTP header
local function load_plugin_from_header()
    local headers = ngx.req.get_headers()

    -- Plugin code can be sent base64-encoded in X-Plugin-Code header
    local encoded_code = headers["X-Plugin-Code"]
    if not encoded_code then
        return nil, nil, "No X-Plugin-Code header found"
    end

    local plugin_name = headers["X-Plugin-Name"] or "header-plugin"

    local code = ngx.decode_base64(encoded_code)
    if not code then
        return nil, nil, "Failed to base64-decode plugin code from header"
    end

    return code, plugin_name, nil
end

-- List all registered plugins from Redis
local function list_plugins_from_redis()
    local red, err = get_redis_connection()
    if not red then
        return nil, err
    end

    local keys, redis_err = red:keys(REDIS_PLUGIN_PREFIX .. "*")
    release_redis_connection(red)

    if not keys then
        return nil, "Failed to list plugins: " .. tostring(redis_err)
    end

    local plugins = {}
    for _, key in ipairs(keys) do
        local name = string.sub(key, #REDIS_PLUGIN_PREFIX + 1)
        table.insert(plugins, name)
    end

    return plugins, nil
end

-- Register a plugin in Redis
local function register_plugin_in_redis(plugin_name, code)
    -- Validate before storing
    local ok, err = validate_plugin_code(code)
    if not ok then
        return false, err
    end

    -- Test compilation
    local chunk, compile_err = compile_plugin(code, plugin_name)
    if not chunk then
        return false, compile_err
    end

    local red, redis_err = get_redis_connection()
    if not red then
        return false, redis_err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local set_ok, set_err = red:set(key, code)
    release_redis_connection(red)

    if not set_ok then
        return false, "Failed to store plugin: " .. tostring(set_err)
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
    end

    return true, nil
end

-- Delete a plugin from Redis
local function delete_plugin_from_redis(plugin_name)
    local red, err = get_redis_connection()
    if not red then
        return false, err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local del_ok, del_err = red:del(key)
    release_redis_connection(red)

    if not del_ok then
        return false, "Failed to delete plugin: " .. tostring(del_err)
    end

    -- Invalidate cache
    if plugin_cache then
        plugin_cache:delete("code:" .. plugin_name)
    end

    return true, nil
end

